entity bd_quad_vmix_dp_smartconnect_0_1_proc_sys_reset is
  port (
    interconnect_aresetn : out STD_LOGIC_VECTOR ( 0 to 0 );
    aclk : in STD_LOGIC;
    aresetn : in STD_LOGIC
  );
  attribute ORIG_REF_NAME : string;
  attribute ORIG_REF_NAME of bd_quad_vmix_dp_smartconnect_0_1_proc_sys_reset : entity is "proc_sys_reset";
end bd_quad_vmix_dp_smartconnect_0_1_proc_sys_reset;

architecture STRUCTURE of bd_quad_vmix_dp_smartconnect_0_1_proc_sys_reset is
  signal SEQ_n_0 : STD_LOGIC;
  signal lpf_int : STD_LOGIC;
  attribute box_type : string;
  attribute box_type of \ACTIVE_LOW_BSR_OUT_DFF[0].FDRE_BSR_N\ : label is "PRIMITIVE";
begin
\ACTIVE_LOW_BSR_OUT_DFF[0].FDRE_BSR_N\: unisim.vcomponents.FDRE
    generic map(
      INIT => '0',
      IS_C_INVERTED => '0',
      IS_D_INVERTED => '0',
      IS_R_INVERTED => '0'
    )
        port map (
      C => aclk,
      CE => '1',
      D => SEQ_n_0,
      Q => interconnect_aresetn(0),
      R => '0'
    );
EXT_LPF: entity work.bd_quad_vmix_dp_smartconnect_0_1_lpf
     port map (
      aclk => aclk,
      aresetn => aresetn,
      lpf_int => lpf_int
    );
SEQ: entity work.bd_quad_vmix_dp_smartconnect_0_1_sequence_psr
     port map (
      aclk => aclk,
      bsr_reg_0 => SEQ_n_0,
      lpf_int => lpf_int
